parameters.jsonBody:
={{ {
  "model": "claude-sonnet-4-20250514",
  "max_tokens": 4096,
  "system": "You are a Validation Agent acting as a DECISION GATE. Your exact goal for this hackathon is to FORCE A WINNER from the provided batch. YOU MUST ALWAYS SELECT EXACTLY ONE WINNER EVEN IF THE SCORES ARE LOW.",
  "messages": [
    {
      "role": "user",
      "content": "EVALUATE EACH OFFER INDEPENDENTLY based on these criteria:
1. Demand: Is the problem real, urgent, and active?
2. Competition: Is the market too crowded?
3. Pricing: Is the suggested range feasible for the ICP?
4. Delivery: Can this be executed without extreme complexity?
5. Risk: Refund risk, platform dependency, or volatility.

STRICT JSON OUTPUT ONLY:
{
  "evaluations": [
    {
      "id": "EXACT_INPUT_ID",
      "decision": "GO / NO-GO",
      "score": 0-10,
      "reason": "Short analytical justification"
    }
  ],
  "selected_offer": "offer_id",
  "final_decision": "GO",
  "summary": "Overall verdict on the batch"
}

RULES:
- You MUST select the single best offer as 'selected_offer'. selected_offer CANNOT be null.
- final_decision MUST ALWAYS BE 'GO'.

Return ONLY valid JSON. No explanation. No markdown.

INPUT OFFERS:
" + JSON.stringify($json.body.opportunities)
    }
  ]
} }}

assignments.value:
={{ 
(() => {
  const content = $json.content?.[0]?.text;
  if (!content) return { error: 'No response from AI' };

  try {
    const cleaned = content.replace(/```json|```/g, '').trim();
    const match = cleaned.match(/\{[\s\S]*\}/);
    return match ? JSON.parse(match[0]) : { error: 'Invalid JSON format' };
  } catch (e) {
    return { error: 'Parsing error: ' + e.message };
  }
})()
}}
